As an AI language model, I cannot generate visual components, but I can provide the logical components of the game. Here is a basic JavaScript code for a Tic Tac Toe game:

```
// define the game board
const board = [
  ['', '', ''],
  ['', '', ''],
  ['', '', '']
];

// initialize variables
let currentPlayer = 'X';
let gameEnd = false;

// function to check for wins
function checkWin() {
  // check rows
  for (let i = 0; i < 3; i++) {
    if (board[i][0] === currentPlayer && board[i][1] === currentPlayer && board[i][2] === currentPlayer) {
      return true;
    }
  }

  // check columns
  for (let j = 0; j < 3; j++) {
    if (board[0][j] === currentPlayer && board[1][j] === currentPlayer && board[2][j] === currentPlayer) {
      return true;
    }
  }

  // check diagonals
  if (board[0][0] === currentPlayer && board[1][1] === currentPlayer && board[2][2] === currentPlayer) {
    return true;
  }
  if (board[0][2] === currentPlayer && board[1][1] === currentPlayer && board[2][0] === currentPlayer) {
    return true;
  }

  // no winner yet
  return false;
}

// function to print the game board
function printBoard() {
  console.log(board[0][0] + ' | ' + board[0][1] + ' | ' + board[0][2]);
  console.log('--+---+--');
  console.log(board[1][0] + ' | ' + board[1][1] + ' | ' + board[1][2]);
  console.log('--+---+--');
  console.log(board[2][0] + ' | ' + board[2][1] + ' | ' + board[2][2]);
}

// function to make a move
function makeMove(row, col) {
  if (gameEnd) {
    console.log('Game over!');
    return;
  }
  if (board[row][col] !== '') {
    console.log('This move has already been made!');
    return;
  }
  board[row][col] = currentPlayer;
  printBoard();
  if (checkWin()) {
    console.log('Player ' + currentPlayer + ' wins!');
    gameEnd = true;
    return;
  }
  if (currentPlayer === 'X') {
    currentPlayer = 'O';
  } else {
    currentPlayer = 'X';
  }
}

// start the game
printBoard();

// example of making a move
makeMove(1, 1);
```

This is a basic implementation of the game logic that can be used on the backend of a web app or game. The next step would be to add visual components such as buttons or a game board display for players to interact with.

Here is example code to implement a Tic Tac Toe game in a browser using HTML, CSS, and JavaScript:

