**app.js**

```
// define the game board
const board = [
  ['', '', ''],
  ['', '', ''],
  ['', '', '']
];

// initialize variables
let currentPlayer = 'X';
let gameEnd = false;

// define DOM elements
const cells = document.querySelectorAll('.cell');
const status = document.getElementById('status');
const restartButton = document.getElementById('restart');

// function to print the game board
function printBoard() {
  for (let i = 0; i < 9; i++) {
    cells[i].textContent = board[Math.floor(i / 3)][i % 3];
  }
}

// function to check for wins
function checkWin() {
  // check rows
  for (let i = 0; i < 3; i++) {
    if (board[i][0] === currentPlayer && board[i][1] === currentPlayer && board[i][2] === currentPlayer) {
      return true;
    }
  }

  // check columns
  for (let j = 0; j < 3; j++) {
    if (board[0][j] === currentPlayer && board[1][j] === currentPlayer && board[2][j] === currentPlayer) {
      return true;
    }
  }

  // check diagonals
  if (board[0][0] === currentPlayer && board[1][1] === currentPlayer && board[2][2] === currentPlayer) {
    return true;
  }
  if (board[0][2] === currentPlayer && board[1][1] === currentPlayer && board[2][0] === currentPlayer) {
    return true;
  }

  // no winner yet
  return false;
}

// function to make a move
function makeMove(row, col) {
  if (gameEnd) {
    return;
  }
  if (board[row][col] !== '') {
    return;
  }
  board[row][col] = currentPlayer;
  printBoard();
  if (checkWin()) {
    status.textContent = 'Player ' + currentPlayer + ' wins!';
    gameEnd = true;
    return;
  }
  if (board.every(row => row.every(cell => cell !== ''))) {
    status.textContent = 'Tie game!';
    gameEnd = true;
    return;
  }
  currentPlayer = (currentPlayer === 'X') ? 'O' : 'X';
  status.textContent = 'Player ' + currentPlayer + '\'s turn';
}

// function to reset the game
function resetGame() {
  for (let i = 0; i < 3; i++) {
    for (let j = 0; j < 3; j++) {
      board[i][j] = '';
    }
  }
  printBoard();
  currentPlayer = 'X';
  gameEnd = false;
  status.textContent = 'Player ' + currentPlayer + '\'s turn';
}

// add event listeners
cells.forEach(cell => cell.addEventListener('click', () => {
  makeMove(Math.floor(cell.id / 3), cell.id % 3);
}));
restartButton.addEventListener('click', resetGame);

// initialize game
printBoard();
status.textContent = 'Player ' + currentPlayer + '\'s turn';
```

To deploy this Tic Tac Toe game on a web server, follow these steps:

1. Create a new folder on your computer and save the three files (`index.html`, `style.css`, and `app.js`) in it.
2. Open your web server software (such as Apache or Nginx) or create a new web server instance (such as using Node.js).
3. Copy the folder containing the Tic Tac Toe game files into the web server's root directory.
4. Start the web server.
5. Open your web browser and navigate to `http://localhost:<port number>/index.html`, where `<port number>` is the port number that your web server is listening on.
6. The Tic Tac Toe game should now be displayed in your browser and ready to play!
